}

impl CSSContainerRule {
    fn new_inherited(parent_stylesheet: &CSSStyleSheet, container_rule: Arc<ContainerRule>) -> CSSContainerRule {
        let list = container_rule.rules.clone();
        CSSContainerRule {
            cssconditionrule: CSSConditionRule::new_inherited(parent_stylesheet, list),
            container_rule: RefCell::new(container_rule),
        }
    }

    pub(crate) fn new(
        window: &Window,
        parent_stylesheet: &CSSStyleSheet,
        container_rule: Arc<ContainerRule>,
        can_gc: CanGc,
    ) -> DomRoot<CSSContainerRule> {
        reflect_dom_object(
            Box::new(CSSContainerRule::new_inherited(parent_stylesheet, container_rule)),
            window,
            can_gc,
        )
    }

    /// <https://drafts.csswg.org/css-conditional-5/#the-csscontainerrule-interface>
    pub(crate) fn get_condition_text(&self) -> DOMString {
        let guard = self.cssconditionrule.shared_lock().read();
        let rule = self.container_rule.borrow();

        let mut text = String::new();

        // Add the container name if present
        if !rule.name.is_empty() {
            text.push_str(&rule.name);
            text.push(' ');
        }

        // Add the query
        let query_str = rule.query.to_css_string();
        text.push_str(&query_str);

        text.into()
    }

    pub(crate) fn update_rule(&self, container_rule: Arc<ContainerRule>, guard: &SharedRwLockReadGuard) {
        self.cssconditionrule
            .update_rules(container_rule.rules.clone(), guard);
        *self.container_rule.borrow_mut() = container_rule;
    }
}

impl SpecificCSSRule for CSSContainerRule {
    fn ty(&self) -> CssRuleType {
        CssRuleType::Container
    }

    fn get_css(&self) -> DOMString {
        let guard = self.cssconditionrule.shared_lock().read();
        self.container_rule.borrow().to_css_string(&guard).into()
    }
}

impl CSSContainerRuleMethods<crate::DomTypeHolder> for CSSContainerRule {
    /// <https://drafts.csswg.org/css-conditional-5/#the-csscontainerrule-interface>
    fn ContainerName(&self) -> DOMString {
        self.container_rule.borrow().name.clone().into()
    }

    fn ContainerQuery(&self) -> DOMString {
        self.container_rule.borrow().query.to_css_string().into()
    }

    fn ConditionText(&self) -> DOMString {
        self.get_condition_text()
    }
}

